import React, { useEffect } from 'react';
import { HashRouter as Router, Switch, Route } from "react-router-dom"; // , Redirect
import { useData } from './contexts/index';
import { Layout } from './components';
import {
  LandingPage,
  BlogPage,
  SingleBlogPage,
  ErrorPage,
  Topics,
  Topic
} from './pages/index';

const App = () => {
  const { loading, setLoading, setSite } = useData();

  useEffect(() => {
    const fetchData = async () => {
      try {
        const result = await fetch(`https://raw.githubusercontent.com/SanjayGoraniya/SanjayGoraniya/main/json/site.json`);
        const body = await result.json();
        setSite(body);
        setLoading(false);
      } catch (err) {
        setLoading(false);
      }
    }
    fetchData();
  }, [setLoading, setSite]);

  useEffect(() => {
    document.body.classList.toggle("siteLoading", loading);
    const removeLoading = () => {
      if(loading) {
        setLoading(false);
      }
    }
    removeLoading();
  }, [loading, setLoading]);

  return (
    <Router basename={process.env.PUBLIC_URL || '/'}>
      <Layout>
        <Switch>
          <Route exact path="/" component={LandingPage} />
          <Route exact path="/topics" component={Topics} />
          <Route path="/topics/:topic" component={Topic} />
          <Route exact path="/blog" component={BlogPage} />
          <Route path="/blog/:slug" component={SingleBlogPage} />
          <Route component={ErrorPage} />
        </Switch>
      </Layout>
    </Router>
  );
}

export default App;