import React from 'react';
import { Link } from 'react-router-dom';
import { useData } from '../contexts/index';
import useQuery from '../hooks/useQuery';
import { slugify } from '../utils';
import { Page } from './';

const Topics = () => {
    const query = useQuery();
    const showPending = query.has('pending');
    const { site: { data: { topics: _topics = [], allTopics = [] } } } = useData();
    var topics = [];
    // Show list of pending topics only
    if(showPending) {
        let aliases = _topics.reduce((list, { aliases }) => list.concat(aliases), []).map((topic) => topic.toLowerCase());
        topics = allTopics.filter(({ title }) => !aliases.includes(title.toLowerCase()));
    }
    if(!showPending) {
        topics = _topics.map(({aliases, name}) => ({ name, title: aliases?.[0] ? aliases[0] : slugify(name)}))   
    }
    
    return (
        <Page title="Topics">
            <section className="section topics">
                <h2 className="section__title">Topics</h2>
                <div className="section__content">
                    <div className="topics__list">
                        {topics.map(({ title, name }, index) => {
                            return <Link key={index} to={`/topics/${title}`} className="topic">
                                <div className="topic__title">
                                    <div className="topic__title__tag">
                                        #
                                    </div>
                                    <h3>{name}</h3>
                                </div>
                            </Link>
                        })}
                    </div>
                </div>
            </section>
        </Page>
    )
}

export default Topics;