import React from 'react';
import { Link } from 'react-router-dom';
import { useData } from '../contexts/index';
import { Page } from './';
// import * as yaml from 'yaml-front-matter';
// import truncate from 'lodash.truncate';


const Topic = (props) => {
  const { site: { data: { topics = [] } } } = useData();

  // const [topic, setTopic] = React.useState({});
  // React.useEffect(() => {
  //   fetch("https://raw.githubusercontent.com/github/explore/main/topics/"+props.match.params.topic+"/index.md")
  //   .then(async (res) => {
  //     const contents = await res.text();
  //     console.log("RES", contents);
  //     const _metadata = yaml.loadFront(contents);
  //     _metadata.preview = _metadata['__content'].trim();
  //     delete _metadata['__content'];
  //     console.log("_META", _metadata);
  //     setTopic(_metadata);
  //   })
  //   .catch((error) => {
  //     console.log("ERROR", error)
  //   })
  // }, []);

  const topic = topics.find((topic) => topic.aliases.map((aliase) => aliase.toLowerCase()).includes(props.match.params.topic.toLowerCase())) || topics.javascript;

  if (!topic) {
    return (
      <Page title={props.match.params.topic.toLowerCase()}>
        <section className="section topics">
          <div className="section__content">
            <div className="topic__title">
              <div className="topic__title__tag">
                #
              </div>
              <h1>{props.match.params.topic.toLowerCase()}</h1>
            </div>
            <div className="topic__not__found">
              The <strong>{props.match.params.topic.toLowerCase()}</strong> topic hasn't been added in the list, yet.
            </div>
            <Link className="email-link" rel="noreferrer" to="/topics">Explore topics</Link>
          </div>
        </section>
      </Page>
    )
  }
  return (
    <Page title={"Topic : " + topic.name.toLowerCase()}>
      <section className="section topics">
        <div className="section__content">
          <div className="topic__title">
            <div className="topic__title__tag">
              #
            </div>
            <h1>{topic.name}</h1>
          </div>

          <div className="topic__details">
            {!!topic.createdBy && (
              <p className="createdby__wrapper">
                Created by <span className="createdby">{topic.createdBy}</span>
              </p>
            )}
            {!!topic.released && (
              <p className="createdby__wrapper">
                Released <span className="createdby">{topic.released}</span>
              </p>
            )}

            {!!topic.website && (
              <a href={topic.website} title={`${topic.name} website link`} target="_blank" rel="noopener noreferrer">
                Website
              </a>
            )}
            {!!topic.wikipedia && <>
              <br />
              <a href={topic.wikipedia} title={`${topic.name} wikipedia link`} target="_blank" rel="noopener noreferrer">
                Wikipedia
              </a>
            </>}
          </div>

          <div className="topic__description">
            {!!topic.logo && <div className="topic__img">
              <img src={topic.logo} width="100" height="100" alt={`${topic.name} logo`} />
            </div>}
            <div className="description__wrapper">
              <p>{topic.description}</p>
            </div>
          </div>
          {!!topic?.related?.length && <div className="related__topics">
            <h2>
              Related Topics
            </h2>
            {topic.related.map((relatedItem) => {
              return <Link key={relatedItem} title={"Topic: " + relatedItem} to={"/topics/" + relatedItem} className="topic__tag">
                {relatedItem}
              </Link>
            })}
          </div>}
        </div>
      </section>
    </Page>
  )
}

export default Topic;