import React from 'react';
import { SectionTitle } from './';

const Background = ({email}) => {
    return (
        <section id="background" className="section background">
            <SectionTitle title="Background" />
            <div className="section__content">
                <p>
                    I'm currently freelance Web Developer. As a Web Developer, I enjoy bridging the gap between development and design — combining my
                    technical knowledge with my keen eye for design to create a beautiful product. 
                </p>
                <p>
                    My goal is to always build applications that are scalable and efficient under the hood while 
                    providing engaging, pixel-perfect user experiences. Interested in role with company promoting 
                    best practices and offering diverse customer projects.
                </p>
                <p>
                    {/* Although I'm not currently looking for any new opportunities,&nbsp;  */}
                    My inbox is always open whether you have a question or just want to <a className="underline-link" href={email}>say hi</a>, 
                    I'll try my best to get back to you!
                </p>
            </div>
        </section>

    )
}
export default Background;