/**
 * @name slugify
 * @description - Slugify the given string which can be used as param in link.
 * @param {String} string - string which needs to be slugify.
 * @return {String} - Slugified string.
 */

const slugify = string =>
    string && string
        .match(/[A-Z]{2,}(?=[A-Z][a-z]+[0-9]*|\b)|[A-Z]?[a-z]+[0-9]*|[A-Z]|[0-9]+/g)
        .map(x => x.toLowerCase())
        .join('-');

export default slugify;